@article{williamson2016activity,
  title = {Shh and ZRS enhancer colocalisation is specific to the zone of polarising activity},
  author = {Iain Williamson, Laura A. Lettice, Robert E. Hill, Wendy A. Bickmore},
  year = {2016},
  journal = {Development},
  doi = {10.1242/dev.139188},
  url = {https://doi.org/10.1242/dev.139188},
  abstract = {Acheiropodia, congenital limb truncation, is associated with homozygous deletions in the LMBR1 gene around ZRS, an enhancer regulating SHH during limb development. How these deletions lead to this phenotype is unknown. Using whole-genome sequencing, we fine-mapped the acheiropodia-associated region to 12 kb and show that it does not function as an enhancer. CTCF and RAD21 ChIP-seq together with 4C-seq and DNA FISH identify three CTCF sites within the acheiropodia-deleted region that mediate the interaction between the ZRS and the SHH promoter. This interaction is substituted with other CTCF sites centromeric to the ZRS in the disease state. Mouse knockouts of the orthologous 12 kb sequence have no apparent abnormalities, showcasing the challenges in modelling CTCF alterations in animal models due to inherent motif differences between species. Our results show that alterations in CTCF motifs can lead to a Mendelian condition due to altered enhancer–promoter interactions. Acheiropodia is associated with homozygous deletions in the LMBR1 gene around ZRS, an enhancer regulating SHH during limb development, but how these deletions lead to this phenotype is unknown. Here the authors use whole-genome sequencing, ChIP-seq, 4C-seq and DNA FISH to show that alterations in CTCF motifs are responsible via altered enhancer–promoter interactions.}
}
